    59	void nr_pusch_codeword_scrambling_uci(uint8_t *in, uint32_t size, uint32_t Nid, uint32_t n_RNTI, uint32_t* out)
    60	{
    61	  uint32_t *seq = gold_cache((n_RNTI << 15) + Nid, (size + 31) / 32);
    62	  for (int i=0; i<size; i++) {
    63	    int idx = i / 32;
    64	    int b_idx = i % 32;
    65	    if (in[i]==NR_PUSCH_x)
    66	      out[idx] ^= 1 << b_idx;
    67	    else if (in[i]==NR_PUSCH_y){
    68	      if (b_idx)
    69	        out[idx] ^= (out[idx] & (1 << (b_idx - 1))) << 1;
    70	      else{
    71	        uint32_t temp_out = out[idx - 1];
    72	        out[idx] ^= temp_out >> 31;
    73	      }
    74	    }
    75	    else
    76	      out[idx] ^= (((in[i]) & 1) ^ ((seq[idx] >> b_idx) & 1)) << b_idx;
    77	    //printf("i %d b_idx %d in %d s 0x%08x out 0x%08x\n", i, b_idx, in[i], s, *out);
    78	  }
    79	}
