    81	void nr_pusch_codeword_scrambling(uint8_t *in, uint32_t size, uint32_t Nid, uint32_t n_RNTI, bool uci_on_pusch, uint32_t* out)
    82	{
    83	  if (uci_on_pusch)
    84	    nr_pusch_codeword_scrambling_uci(in, size, Nid, n_RNTI, out);
    85	  else
    86	    nr_codeword_scrambling(in, size, 0, Nid, n_RNTI, out);
    87	}
