   104	/*
   105	DMRS mapping in a RB for Type 1.
   106	Mapping as in TS 38.211 6.4.1.1.3 k = 4n + 2k^prime + delta
   107	*/
   108	static void map_dmrs_type1_cdm1_rb(const unsigned int delta, const c16_t *dmrs, c16_t *out)
   109	{
   110	  *(out + delta) = *dmrs++;
   111	  *(out + delta + 2) = *dmrs++;
   112	  *(out + delta + 4) = *dmrs++;
   113	  *(out + delta + 6) = *dmrs++;
   114	  *(out + delta + 8) = *dmrs++;
   115	  *(out + delta + 10) = *dmrs++;
   116	}
