   118	/*
   119	Data in DMRS symbol for Type 1, NumCDMGroupNoData = 1 and delta 0 (antenna port 0 and 1).
   120	There is no data in DMRS symbol for other scenarios in type 1.
   121	*/
   122	static void map_data_dmrs_type1_cdm1_rb(const unsigned int num_cdm_no_data, const c16_t *data, c16_t *out)
   123	{
   124	  *(out + 1) = *data++;
   125	  *(out + 3) = *data++;
   126	  *(out + 5) = *data++;
   127	  *(out + 7) = *data++;
   128	  *(out + 9) = *data++;
   129	  *(out + 11) = *data++;
   130	}
