   135	/*
   136	Map DMRS for type 2
   137	Mapping as in TS 38.211 6.4.1.1.3 k = 6n + k^prime + delta
   138	*/
   139	static void map_dmrs_type2_rb(const unsigned int delta, const c16_t *dmrs, c16_t *out)
   140	{
   141	  memcpy(out + delta, dmrs, sizeof(c16_t) * NR_DMRS_TYPE2_CDM_GRP_SIZE);
   142	  out += (NR_DMRS_TYPE2_CDM_GRP_SIZE * NR_DMRS_TYPE2_NUM_CDM_GRP);
   143	  dmrs += NR_DMRS_TYPE2_CDM_GRP_SIZE;
   144	  memcpy(out + delta, dmrs, sizeof(c16_t) * NR_DMRS_TYPE2_CDM_GRP_SIZE);
   145	}
